// 按级别获取试卷
export const getExamsByLevel = (level: string): ExamPaper[] => {
  return exams.filter(exam => exam.level === level);
};

// 获取所有级别
export const getExamLevels = () => {
  return [
    { id: 'elementary', name: '小学', nameEn: 'Elementary', color: 'bg-green-500' },
    { id: 'junior', name: '初中', nameEn: 'Junior High', color: 'bg-blue-500' },
    { id: 'senior', name: '高中', nameEn: 'Senior High', color: 'bg-purple-500' },
    { id: 'university', name: '大学', nameEn: 'University', color: 'bg-amber-500' },
  ];
};
